import{_ as t,c as a,a1 as s,o as n}from"./chunks/framework.BDxlaA_J.js";const g=JSON.parse('{"title":"Detecting DoS Attack traffic","description":"","frontmatter":{},"headers":[],"relativePath":"categories/ethical-hacking-labs/9-denial-of-service/3-Detecting-DoS-Traffic.md","filePath":"categories/ethical-hacking-labs/9-denial-of-service/3-Detecting-DoS-Traffic.md"}'),o={name:"categories/ethical-hacking-labs/9-denial-of-service/3-Detecting-DoS-Traffic.md"};function r(i,e,c,d,p,l){return n(),a("div",null,e[0]||(e[0]=[s(`<h1 id="detecting-dos-attack-traffic" tabindex="-1">Detecting DoS Attack traffic <a class="header-anchor" href="#detecting-dos-attack-traffic" aria-label="Permalink to &quot;Detecting DoS Attack traffic&quot;">​</a></h1><p>KFSensor is a Windows-based honeypot IDS. It acts as a honeypot to attract and detect hackers and worms by simulating vulnerable system services and Trojans. By acting as a decoy server, it can divert attacks form critical system and provides a higher level of information than firewalls and NIDS alone.</p><p>KFSensor Free Trial: <a href="http://www.keyfocus.net/kfsensor/" target="_blank" rel="noreferrer">http://www.keyfocus.net/kfsensor/</a> Wireshark: <a href="https://www.wireshark.org/" target="_blank" rel="noreferrer">https://www.wireshark.org/</a></p><h3 id="objectives" tabindex="-1">Objectives <a class="header-anchor" href="#objectives" aria-label="Permalink to &quot;Objectives&quot;">​</a></h3><ul><li>Detect DoS attack using KFSensor</li><li>Analyze the incoming packet dump using Wireshark</li></ul><h3 id="requisites" tabindex="-1">Requisites <a class="header-anchor" href="#requisites" aria-label="Permalink to &quot;Requisites&quot;">​</a></h3><ul><li>Windows 10 virtual machine</li><li>Windows Server 2012 or 2016 virtual machine</li><li>Kali Linux virtual machine</li></ul><h2 id="setting-up" tabindex="-1">Setting up <a class="header-anchor" href="#setting-up" aria-label="Permalink to &quot;Setting up&quot;">​</a></h2><ol><li><p>Install <a href="http://www.keyfocus.net/kfsensor/" target="_blank" rel="noreferrer">KFSensor</a> and <a href="https://www.wireshark.org/" target="_blank" rel="noreferrer">Wireshark</a> on Windows 10 virtual machine.</p></li><li><p>Launch the KFSensor as Administrator.</p></li><li><p>Click on <strong>Settings</strong> on the top menu and Set Up Wizard: <img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/9296013460b912b31656952b31c5c8fb343b073d/kfsensor-1.png" alt="kfsensor"> Leave the options as default until and stop on DoS options.</p></li><li><p>Select <strong>Cautious</strong> from Denial of Service Options drop-down list, and select <strong>Enable packet dump files</strong> from the <strong>Network Protocol Analyzer</strong> drop-down list: <img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/9296013460b912b31656952b31c5c8fb343b073d/kfsensor-2.png" alt="kfsensor2"></p></li><li><p>Click next and Finish the wizard: <img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/9296013460b912b31656952b31c5c8fb343b073d/kfsensor-3.png" alt="kfsensor3"></p></li></ol><p>On the left panel you will see the FTP icon is green, and the FTP section is empty, it means currently there is no traffic through port 21.</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/d2a685936b7fe3a16bbc3f53e6a9462c0cea0477/kfsensor-4.png" alt="kfsensor4"></p><p>Now, the KFSensor is configured to detect the DoS attacks.</p><h2 id="perform-dos-attack" tabindex="-1">Perform DoS Attack <a class="header-anchor" href="#perform-dos-attack" aria-label="Permalink to &quot;Perform DoS Attack&quot;">​</a></h2><p>Switch to the Kali Linux and open a new terminal window.</p><ol><li>Check if the port 21 is open: <code>nmap -p 21 &lt;Windows 10 IP address&gt;</code></li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Starting Nmap 7.80 ( https://nmap.org ) at 2020-01-22 14:02 EST</span></span>
<span class="line"><span>Nmap scan report for 10.0.2.45</span></span>
<span class="line"><span>Host is up (0.00051s latency).</span></span>
<span class="line"><span></span></span>
<span class="line"><span>PORT   STATE SERVICE</span></span>
<span class="line"><span>21/tcp open  ftp</span></span></code></pre></div><p><strong>As you can see above, the port 21 is open.</strong></p><p>Let&#39;s use this port to flood the target:</p><ol start="2"><li>Perform <strong>SYN flooding</strong> by typing: <code>hping3 -d 100 -S -p 21 --flood &lt;Windows 10 IP Address&gt;</code></li></ol><table tabindex="0"><thead><tr><th>Parameter</th><th>Description</th></tr></thead><tbody><tr><td><code>-S</code></td><td>SYN Flooding</td></tr><tr><td><code>-p 21</code></td><td>Port 21</td></tr><tr><td><code>-d 100</code></td><td>Data size of each packet (bytes)</td></tr></tbody></table><p>After you enter the command, switch to the <strong>Windows 10</strong>, observe that the machine is almost frozen, which means that the resources of Windows are completely exhausted. This means that the DoS attack is being successfully performed.</p><p>Switch back to the <strong>Kali Linux</strong> and press <strong>Ctrl+C</strong> to terminate SYN flooding.</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/69d1c60b4927909ac69784c963ad1712c5f5fe0a/kfsensor-7.png" alt="hping3-terminate"></p><h2 id="detecting-dos-attack" tabindex="-1">Detecting DoS Attack <a class="header-anchor" href="#detecting-dos-attack" aria-label="Permalink to &quot;Detecting DoS Attack&quot;">​</a></h2><p>Switch to the <strong>Windows 10</strong>, you should now be able to access it.</p><p>Now the FTP icon in the left pane changes to <strong>red</strong>, and the FTP section in the right pane is flooded with events.</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/69d1c60b4927909ac69784c963ad1712c5f5fe0a/kfsensor-8.png" alt="kfsensor9"></p><p>Scroll down and try to find an event named <strong>DOS Attack</strong></p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/19219e6d8c9e72aa7349794f40ecb1ad02daffbd/kfsensor-9.png" alt="kfsensor10"></p><p>This concludes that KFSensor has detected the DoS attack.</p><p>Choose another random event and double click it to show the event details.</p><p>On the Event window, which contains the event summary, you can see the severity level of the event <strong>(High)</strong>, the description of the event <strong>(Syn Scan)</strong>, the visitor of the event <strong>(Attacker machine&#39;s IP address)</strong>, sensor name <strong>(FTP)</strong>, and so on as you can see below.</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/19219e6d8c9e72aa7349794f40ecb1ad02daffbd/kfsensor-10.png" alt="kfsensor11"></p><h2 id="analyze-packet-dump-on-wireshark" tabindex="-1">Analyze Packet Dump on Wireshark <a class="header-anchor" href="#analyze-packet-dump-on-wireshark" aria-label="Permalink to &quot;Analyze Packet Dump on Wireshark&quot;">​</a></h2><p>Next, analyze the packet dump file containing the traffic captured during the DoS attack. KFSensor stores the packet dump file on <strong>C:\\kfsensor\\dumps</strong> by default.</p><p>Open the Wireshark and click <strong>File &gt; Open</strong> and open the packet dump stored in <strong>C:\\kfsensor\\dumps</strong></p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/84f8b3324442d6d26f744a9566c74dd7964bc866/kfsensor-11.png" alt="kfsensor-wireshark11"></p><p>Wireshark loads the file and displays the packet&#39;s details, as show above.</p><p>You can analyze the packets to get information related to headers of the packets, source IP addresses, and so on.</p>`,39)]))}const f=t(o,[["render",r]]);export{g as __pageData,f as default};
